800 // Identify and Merge consecutive loads recursively which is of the form
801 // (ZExt(L1) << shift1) | (ZExt(L2) << shift2) -> ZExt(L3) << shift1
802 // (ZExt(L1) << shift1) | ZExt(L2) -> ZExt(L3)
803 static bool foldLoadsRecursive(Value *V, LoadOps &LOps, const DataLayout &DL,
804                                AliasAnalysis &AA, bool IsRoot = false) {
805   uint64_t ShAmt2;
806   Value *X;
807   Instruction *L1, *L2;
808 
809   // For the root instruction, allow multiple uses since the final result
810   // may legitimately be used in multiple places. For intermediate values,
811   // require single use to avoid creating duplicate loads.
812   if (!IsRoot && !V->hasOneUse())
813     return false;
814 
815   if (!match(V, m_c_Or(m_Value(X),
816                        m_OneUse(m_ShlOrSelf(m_OneUse(m_ZExt(m_Instruction(L2))),
817                                             ShAmt2)))))
818     return false;
819 
820   if (!foldLoadsRecursive(X, LOps, DL, AA, /*IsRoot=*/false) && LOps.FoundRoot)
821     // Avoid Partial chain merge.
822     return false;
823 
824   // Check if the pattern has loads
825   LoadInst *LI1 = LOps.Root;
826   uint64_t ShAmt1 = LOps.Shift;
827   if (LOps.FoundRoot == false &&
828       match(X, m_OneUse(
829                    m_ShlOrSelf(m_OneUse(m_ZExt(m_Instruction(L1))), ShAmt1)))) {
830     LI1 = dyn_cast<LoadInst>(L1);
831   }
832   LoadInst *LI2 = dyn_cast<LoadInst>(L2);
833 
834   // Check if loads are same, atomic, volatile and having same address space.
835   if (LI1 == LI2 || !LI1 || !LI2 || !LI1->isSimple() || !LI2->isSimple() ||
836       LI1->getPointerAddressSpace() != LI2->getPointerAddressSpace())
837     return false;
838 
839   // Check if Loads come from same BB.
840   if (LI1->getParent() != LI2->getParent())
841     return false;
842 
843   // Find the data layout
844   bool IsBigEndian = DL.isBigEndian();
845 
846   // Check if loads are consecutive and same size.
847   Value *Load1Ptr = LI1->getPointerOperand();
848   APInt Offset1(DL.getIndexTypeSizeInBits(Load1Ptr->getType()), 0);
849   Load1Ptr =
850       Load1Ptr->stripAndAccumulateConstantOffsets(DL, Offset1,
851                                                   /* AllowNonInbounds */ true);
852 
853   Value *Load2Ptr = LI2->getPointerOperand();
854   APInt Offset2(DL.getIndexTypeSizeInBits(Load2Ptr->getType()), 0);
855   Load2Ptr =
856       Load2Ptr->stripAndAccumulateConstantOffsets(DL, Offset2,
857                                                   /* AllowNonInbounds */ true);
858 
859   // Verify if both loads have same base pointers
860   uint64_t LoadSize1 = LI1->getType()->getPrimitiveSizeInBits();
861   uint64_t LoadSize2 = LI2->getType()->getPrimitiveSizeInBits();
862   if (Load1Ptr != Load2Ptr)
863     return false;
864 
865   // Make sure that there are no padding bits.
866   if (!DL.typeSizeEqualsStoreSize(LI1->getType()) ||
867       !DL.typeSizeEqualsStoreSize(LI2->getType()))
868     return false;
869 
870   // Alias Analysis to check for stores b/w the loads.
871   LoadInst *Start = LOps.FoundRoot ? LOps.RootInsert : LI1, *End = LI2;
872   MemoryLocation Loc;
873   if (!Start->comesBefore(End)) {
874     std::swap(Start, End);
875     // If LOps.RootInsert comes after LI2, since we use LI2 as the new insert
876     // point, we should make sure whether the memory region accessed by LOps
877     // isn't modified.
878     if (LOps.FoundRoot)
879       Loc = MemoryLocation(
880           LOps.Root->getPointerOperand(),
881           LocationSize::precise(DL.getTypeStoreSize(
882               IntegerType::get(LI1->getContext(), LOps.LoadSize))),
883           LOps.AATags);
884     else
885       Loc = MemoryLocation::get(End);
886   } else
887     Loc = MemoryLocation::get(End);
888   unsigned NumScanned = 0;
889   for (Instruction &Inst :
890        make_range(Start->getIterator(), End->getIterator())) {
891     if (Inst.mayWriteToMemory() && isModSet(AA.getModRefInfo(&Inst, Loc)))
892       return false;
893 
894     if (++NumScanned > MaxInstrsToScan)
895       return false;
896   }
897 
898   // Make sure Load with lower Offset is at LI1
899   bool Reverse = false;
900   if (Offset2.slt(Offset1)) {
901     std::swap(LI1, LI2);
902     std::swap(ShAmt1, ShAmt2);
903     std::swap(Offset1, Offset2);
904     std::swap(Load1Ptr, Load2Ptr);
905     std::swap(LoadSize1, LoadSize2);
906     Reverse = true;
907   }
908 
909   // Big endian swap the shifts
910   if (IsBigEndian)
911     std::swap(ShAmt1, ShAmt2);
912 
913   // First load is always LI1. This is where we put the new load.
914   // Use the merged load size available from LI1 for forward loads.
915   if (LOps.FoundRoot) {
916     if (!Reverse)
917       LoadSize1 = LOps.LoadSize;
918     else
919       LoadSize2 = LOps.LoadSize;
920   }
921 
