934     LOps.FoundRoot = true;
935     AATags1 = LI1->getAAMetadata();
936   }
937   LOps.LoadSize = LoadSize1 + LoadSize2;
938   LOps.RootInsert = Start;
939 
940   // Concatenate the AATags of the Merged Loads.
941   LOps.AATags = AATags1.concat(AATags2);
